parameters.functionCode:
// Extract order details
const order = $input.first().json;
const productType = order.product_type;
const dataRemaining = order.data_remaining || 0;
const planGb = order.plan_gb;
const status = order.status;

// Refund policy enforcement
let eligible = false;
let reason = "";
let refundType = "none";

// Check product type and eligibility
if (productType === 'residential') {
  // R64-1: Residential data never expires — no partial refund for unused GB
  eligible = false;
  reason = "Residential data carries over and never expires. No partial refund for unused GB.";
  refundType = "not_eligible";
} else if (productType === 'mobile') {
  // Mobile data: 30-day window expires, not the GB
  // Check if within 30 days of fulfillment
  const fulfilledAt = new Date(order.fulfilled_at);
  const now = new Date();
  const daysSinceFulfillment = Math.floor((now - fulfilledAt) / (1000 * 60 * 60 * 24));

  if (daysSinceFulfillment > 30) {
    eligible = false;
    reason = "Mobile data window has expired. No refund available.";
    refundType = "not_eligible";
  } else if (dataRemaining > 0) {
    // Partial refund eligible for mobile
    eligible = true;
    refundType = "partial";
    reason = `Partial refund for ${dataRemaining}GB unused of ${planGb}GB plan.`;
  } else {
    eligible = false;
    reason = "All data has been used. No refund available.";
    refundType = "not_eligible";
  }
} else if (productType === 'isp' || productType === 'datacenter') {
  // ISP/Datacenter: Check if proxy was dead or provider outage
  // For this version: full refund within 24h if proxy was dead
  eligible = false;
  reason = "ISP/Datacenter proxies are non-refundable after delivery unless proxy is dead on arrival.";
  refundType = "not_eligible";
} else {
  eligible = false;
  reason = "Unknown product type. Contact support.";
  refundType = "not_eligible";
}

return [{
  json: {
    eligible,
    reason,
    refundType,
    orderId: order.order_id,
    productType,
    planGb,
    dataRemaining
  }
}];

