// Build rejection message based on product type
const order = $input.first().json;
let message = "";

if (order.productType === 'residential') {
  message = `I can see you've used some of your ${order.planGb}GB Residential plan.\n\nHere's how Residential data works:\n\n✅ Your remaining data carries over\n✅ Data never expires on Residential\n✅ Your GB is safe — use it whenever you want\n\nThere's no time limit on Residential data.\nRenew when you're ready and your GB stays with you.\n\nYou don't lose unused data — so no partial refund is needed there 👍`;
} else if (order.productType === 'mobile') {
  message = `Your Mobile data has a 30-day window.\nIf within 30 days of fulfillment and you have remaining data, a partial refund may be available.\n\nHowever, your data remaining: ${order.dataRemaining}GB\n\nContact support if you'd like to request a partial refund.`;
} else {
  message = `I'm sorry, but ${order.productType} proxies are not eligible for refunds after delivery.\n\nIf your proxy has stopped working, let me know and I'll help with a replacement.`;
}

return [{
  json: {
    message,
    orderId: order.orderId,
    productType: order.productType
  }
}];

